module RefModule(
    input       [1:0]   bin ,

    output  reg [3:0]   out
);

    // 2-to-4 Binary Decoder
    always @(*) begin
        case(bin)
            2'b00: out = 4'b0001;
            2'b01: out = 4'b0010;
            2'b10: out = 4'b0100;
            2'b11: out = 4'b1000;
            default: out = 4'b0000;
        endcase
    end

endmodule
